@namespace Lumeo
@implements IAsyncDisposable
@inject IComponentInteropService Interop

@{
    // Bump a monotonic render generation each time the group's body runs. Items
    // re-register during this render pass (OnParametersSet fires in declaration
    // order for every child a parent re-render produces — insert/remove/Value-
    // change all do this); the parent rebuilds _itemValues from THAT registration
    // sequence (see RegisterItem), so the registry tracks DOM/declaration order
    // instead of a bare !Contains-append-to-tail. #69.
    _generation++;
    var context = new ToggleGroupContext(Type, _selectedItems, Variant, Size, EventCallback.Factory.Create<string>(this, ToggleItem), GetTabIndex, _itemValues, _itemIds, _itemDisabled, RegisterItem, UnregisterItem, SetFocusValue, _generation, _id);
}

<div id="@_id" role="group" class="@CssClass" @onkeydown="HandleKeyDown" @attributes="AdditionalAttributes">
    <CascadingValue Value="context" IsFixed="false">
        @ChildContent
    </CascadingValue>
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public ToggleGroupType Type { get; set; } = ToggleGroupType.Single;
    [Parameter] public ToggleGroupVariant Variant { get; set; } = ToggleGroupVariant.Default;
    [Parameter] public Lumeo.Size Size { get; set; } = Lumeo.Size.Md;
    [Parameter] public string? Value { get; set; }
    [Parameter] public EventCallback<string?> ValueChanged { get; set; }
    [Parameter] public IEnumerable<string>? SelectedValues { get; set; }
    [Parameter] public EventCallback<IEnumerable<string>> SelectedValuesChanged { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly HashSet<string> _selectedItems = new();
    private readonly string _id = LumeoIds.New("togglegroup");

    // Ordered item registry — populated by ToggleGroupItem children. Drives the
    // roving tabindex (one tab stop) and arrow-key focus movement. These three
    // are still exposed read-only via the context (existing call sites read them)
    // but are now REBUILT from the children's registration sequence each render
    // generation rather than appended to with a bare !Contains check. #69.
    private readonly List<string> _itemValues = new();
    private readonly Dictionary<string, string> _itemIds = new();
    private readonly Dictionary<string, bool> _itemDisabled = new();

    // #69: per-render-generation ordered registration log. RegisterItem appends
    // each item (in the OnParametersSet order the current parent render fires
    // them, i.e. DOM/declaration order) under the live generation; the first
    // registration of a new generation snapshots+clears the working buffers so a
    // stale ordering from the previous pass never lingers. Keyed by the item's
    // STABLE id (LumeoIds.New) so a Value rename re-keys in place at the same slot
    // and insert-at-front lands at index 0 instead of being appended to the tail.
    private int _generation;
    private int _builtGeneration = -1;
    private readonly List<(string ItemId, string Value)> _registrationLog = new();

    // PURE @key physical reorder-with-reuse (consumer swaps two SIBLING items'
    // positions WITHOUT changing their Value and WITHOUT an insert/remove, so no
    // child's OnParametersSet fires) is DEFERRED — consistent with the Accordion
    // precedent, which also leaves pure reorder unsolved. Detecting it needs a
    // JS DOM-order read; we deliberately do NOT add that interop here. The
    // tractable insert/remove/Value-change legs below all DO fire OnParametersSet
    // and so are handled by the registration-sequence rebuild.
    private void RegisterItem(string itemId, string value, bool disabled, int generation)
    {
        if (generation != _builtGeneration)
        {
            // First registration of a fresh parent render: start a new ordering.
            _builtGeneration = generation;
            _registrationLog.Clear();
            _itemValues.Clear();
            _itemIds.Clear();
            _itemDisabled.Clear();
        }

        // Re-key in place if this stable item already logged a (now-renamed)
        // value this generation; otherwise append at the current DOM position.
        var existing = _registrationLog.FindIndex(e => e.ItemId == itemId);
        if (existing >= 0)
        {
            var oldValue = _registrationLog[existing].Value;
            if (oldValue != value)
            {
                _itemValues[existing] = value;
                _itemIds.Remove(oldValue);
                _itemDisabled.Remove(oldValue);
            }
            _registrationLog[existing] = (itemId, value);
        }
        else
        {
            _registrationLog.Add((itemId, value));
            _itemValues.Add(value);
        }
        _itemIds[value] = itemId;
        _itemDisabled[value] = disabled;
    }

    // A conditionally-removed item that does NOT trigger a full-fragment re-render
    // still disposes; drop its slot (ownership-guarded by stable id) so the
    // registry never points focus at a vanished button.
    private void UnregisterItem(string itemId, string value)
    {
        var idx = _registrationLog.FindIndex(e => e.ItemId == itemId);
        if (idx < 0) return;
        var loggedValue = _registrationLog[idx].Value;
        _registrationLog.RemoveAt(idx);
        if (idx < _itemValues.Count && _itemValues[idx] == loggedValue)
            _itemValues.RemoveAt(idx);
        else
            _itemValues.Remove(loggedValue);
        if (_itemIds.TryGetValue(loggedValue, out var owner) && owner == itemId)
        {
            _itemIds.Remove(loggedValue);
            _itemDisabled.Remove(loggedValue);
        }
    }

    // #169 focus-anchor sync: the item button wires this to @onfocus and its
    // Toggle handler so _focusValue always reflects the item the user actually
    // reached via mouse/Tab. HandleKeyDown then derives the navigation start index
    // from the TRULY-focused item instead of a stale arrow-chain anchor.
    private void SetFocusValue(string value)
    {
        if (_itemValues.Contains(value)) _focusValue = value;
    }

    // Last-seen bound parameters — lets us distinguish "consumer cleared the
    // binding to null" (sync: clear the selection) from "consumer never binds
    // at all" (uncontrolled usage: leave the internally-toggled selection alone).
    private string? _lastValue;
    private IEnumerable<string>? _lastSelectedValues;

    // CONTROLLED discriminator: the last value/collection we pushed UP via the
    // change callback. Used to detect echoes (parent accepted our edit and
    // re-rendered with the exact value we pushed — do nothing) vs authoritative
    // parent overrides (normalization, programmatic reset, or REJECTION where the
    // parent kept its old value — roll back the UI to the bound value).
    // Must be set BEFORE InvokeAsync because a controlled parent may re-render
    // synchronously inside the callback, and OnParametersSet must see the correct
    // _lastPushed so it can distinguish echo vs. override.
    private string? _lastPushedValue;
    private IEnumerable<string>? _lastPushedSelectedValues;

    private string CssClass => Cx.Merge("flex items-center gap-1", Class);

    // Roving tabindex: the first selected item is the tab stop; if nothing is
    // selected, the first ENABLED item holds it. Arrow keys then move focus among
    // the rest (Radix ToggleGroup: arrows move focus, Enter/Space toggles).
    private string GetTabIndex(string value, bool disabled)
    {
        if (disabled) return "-1";
        var firstSelected = _itemValues.FirstOrDefault(v => _selectedItems.Contains(v) && !IsItemDisabled(v));
        if (firstSelected is not null) return value == firstSelected ? "0" : "-1";
        return _itemValues.FirstOrDefault(v => !IsItemDisabled(v)) == value ? "0" : "-1";
    }

    private bool IsItemDisabled(string value) =>
        _itemDisabled.TryGetValue(value, out var d) && d;

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        // Only the roving-nav keys do anything; bail BEFORE the DOM-order probe on
        // any other key so non-nav keystrokes never reach interop and behaviour is
        // byte-for-byte unchanged (the old handler also no-op'd every other key).
        var isNavKey = e.Key is "ArrowRight" or "ArrowDown" or "ArrowLeft" or "ArrowUp" or "Home" or "End";
        if (!isNavKey || _itemValues.Count == 0) return;

        // Resolve the nav order from the LIVE DOM (#69): a PURE @key reorder MOVES
        // reused ToggleGroupItem instances to new DOM positions WITHOUT firing their
        // OnParametersSet, so the registration-order _itemValues list goes stale.
        // OrderedItems() reprojects it onto the DOM-order item ids; an empty/NULL
        // probe (prerender / JS off / a test that doesn't drive a reorder) falls back
        // to _itemValues verbatim, so the no-reorder path is identical to before.
        var items = await OrderedItems();

        // The reference point for navigation is the item the user is actually on.
        // #169: _focusValue is now kept in sync with real focus (mouse/Tab) via
        // the item's @onfocus + Toggle (SetFocusValue), so prefer it. Only when no
        // real focus has been recorded do we fall back to the current tab stop
        // (first selected, else first enabled) — matching where focus sits when
        // the user tabs in. This stops ArrowRight from a mouse-focused item from
        // navigating off a stale arrow-chain anchor.
        var idx = _focusValue is not null && items.Contains(_focusValue) && !IsItemDisabled(_focusValue)
            ? items.IndexOf(_focusValue)
            : -1;
        if (idx < 0)
        {
            var anchor = items.FirstOrDefault(v => _selectedItems.Contains(v) && !IsItemDisabled(v))
                ?? items.FirstOrDefault(v => !IsItemDisabled(v));
            if (anchor is null) return;
            idx = items.IndexOf(anchor);
        }

        string? target = e.Key switch
        {
            "ArrowRight" or "ArrowDown" => FindNextEnabled(items, idx, 1),
            "ArrowLeft" or "ArrowUp" => FindNextEnabled(items, idx, -1),
            "Home" => items.FirstOrDefault(v => !IsItemDisabled(v)),
            "End" => items.LastOrDefault(v => !IsItemDisabled(v)),
            _ => null
        };
        if (target is null) return;

        _focusValue = target;
        if (_itemIds.TryGetValue(target, out var id))
        {
            try { await Interop.FocusElement(id); }
            catch (JSDisconnectedException) { }
        }
    }

    // The nav value list reordered to match LIVE DOM order. The DOM-order probe
    // returns the toggle-item button ids in document order; we map each id back to
    // its registered value (inverting the value->id registry) and reproject the
    // _itemValues list onto it, appending any registry leftovers the DOM didn't
    // surface. An empty/NULL probe result → the registration order verbatim.
    private async Task<List<string>> OrderedItems()
    {
        var registry = _itemValues;
        // NOTE: a Loose-mode JSInterop (the default test double) returns NULL for an
        // unconfigured string[] invocation — null-guard it, don't assume [].
        string[]? domOrder;
        try
        {
            domOrder = await Interop.GetOrderedDescendantIds(_id, "button[data-toggle-item]");
        }
        catch (JSDisconnectedException) { domOrder = null; }
        catch (ObjectDisposedException) { domOrder = null; }
        catch (InvalidOperationException) { domOrder = null; } // JS unavailable (prerender)

        if (domOrder is not { Length: > 0 }) return registry;

        // Invert value->id into id->value so a document-order id resolves to its value.
        var idToValue = new Dictionary<string, string>(_itemIds.Count);
        foreach (var (value, id) in _itemIds) idToValue[id] = value;

        var remaining = new List<string>(registry);
        var ordered = new List<string>(registry.Count);
        foreach (var id in domOrder)
            if (idToValue.TryGetValue(id, out var value) && remaining.Remove(value))
                ordered.Add(value);
        ordered.AddRange(remaining);
        return ordered;
    }

    // Tracks the last item we moved focus to via arrow keys, so successive
    // presses chain (right, right, right) rather than always restarting from the
    // selected item.
    private string? _focusValue;

    // Operates over the DOM-ordered nav list resolved by OrderedItems() so a keyed
    // reorder steps from the live-DOM neighbour, not the registration-order one.
    private string? FindNextEnabled(List<string> items, int currentIdx, int direction)
    {
        if (items.Count == 0) return null;
        var idx = currentIdx;
        for (var i = 0; i < items.Count; i++)
        {
            idx += direction;
            if (idx < 0) idx = items.Count - 1;
            else if (idx >= items.Count) idx = 0;
            if (idx == currentIdx) return null;
            if (!IsItemDisabled(items[idx])) return items[idx];
        }
        return null;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;
        try
        {
            await Interop.RegisterPreventDefaultKeys(
                _id,
                new[] { "ArrowDown", "ArrowRight", "ArrowUp", "ArrowLeft", "Home", "End" }
                    .Select(k => new Lumeo.Services.PreventDefaultKeyRule(k)).ToArray());
            _pdRegistered = true;
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { }
    }

    private bool _pdRegistered;

    public async ValueTask DisposeAsync()
    {
        if (!_pdRegistered) return;
        try { await Interop.UnregisterPreventDefaultKeys(_id); }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { }
    }

    protected override void OnParametersSet()
    {
        if (Type == ToggleGroupType.Single)
        {
            if (ValueChanged.HasDelegate)
            {
                // CONTROLLED: the parent owns Value and it is authoritative — EXCEPT
                // when it echoes back the exact value we just pushed (_lastPushedValue).
                // A SECOND exception exists ONLY for a null baseline: a consumer that
                // binds ValueChanged purely to OBSERVE, without ever binding Value back,
                // leaves Value at its unbound default (null) on every render — that must
                // NOT be treated as a veto that clobbers the local toggle (Codex P2).
                // This narrow, null-only carve-out is deliberate: a NON-null unchanged
                // baseline is indistinguishable from a genuinely bound Value the parent
                // is choosing to keep pinned (a real veto that must roll the UI back —
                // Codex P2 flagged the broader "any unchanged baseline is a no-op"
                // version of this check for exactly that reason, since it silently
                // preserved a rejected toggle whenever the parent's veto re-render
                // happened to match its own pre-interaction value). Any OTHER incoming
                // value wins: a normalization, programmatic reset, or a REJECTION where
                // the parent kept its old (non-null, bound) value.
                var isEcho = Value == _lastPushedValue;
                var isNullObserverEcho = Value is null && _lastValue is null;
                if (!isEcho && !isNullObserverEcho)
                {
                    _selectedItems.Clear();
                    if (Value is not null) _selectedItems.Add(Value);
                    _lastPushedValue = Value;
                }
            }
            else
            {
                // UNCONTROLLED: keep existing param-change detection.
                if (Value is not null)
                {
                    _selectedItems.Clear();
                    _selectedItems.Add(Value);
                }
                else if (_lastValue is not null)
                {
                    // Bound value was reset to null — drop the stale selection.
                    _selectedItems.Clear();
                }
            }
            _lastValue = Value;
        }
        else if (Type == ToggleGroupType.Multiple)
        {
            if (SelectedValuesChanged.HasDelegate)
            {
                // CONTROLLED: adopt only when SelectedValues is NOT the same object
                // reference we just pushed (reference equality is sufficient: a veto
                // keeps the OLD reference; an echo re-supplies the same list object we
                // handed the parent; a programmatic override supplies a new reference).
                // A SECOND exception exists ONLY when SelectedValues is null AND it was
                // ALSO null on the previous render (_lastSelectedValues) — a consumer
                // that binds SelectedValuesChanged purely to OBSERVE, without ever
                // binding SelectedValues back, keeps supplying its unbound default
                // (null) on every re-render, which must NOT be treated as a veto that
                // clobbers the local toggle (Codex P2). This narrow, null-only carve-out
                // mirrors the Single-mode branch: a NON-null unchanged reference is a
                // genuinely bound SelectedValues the parent is choosing to keep pinned
                // (a real veto that must roll the UI back).
                var isEcho = ReferenceEquals(SelectedValues, _lastPushedSelectedValues);
                var isNullObserverEcho = SelectedValues is null && _lastSelectedValues is null;
                if (!isEcho && !isNullObserverEcho)
                {
                    _selectedItems.Clear();
                    if (SelectedValues is not null)
                        foreach (var v in SelectedValues) _selectedItems.Add(v);
                    _lastPushedSelectedValues = SelectedValues;
                }
            }
            else
            {
                // UNCONTROLLED: keep existing param-change detection.
                if (SelectedValues is not null)
                {
                    _selectedItems.Clear();
                    foreach (var v in SelectedValues) _selectedItems.Add(v);
                }
                else if (_lastSelectedValues is not null)
                {
                    // Bound collection was reset to null — drop the stale selection.
                    _selectedItems.Clear();
                }
            }
            _lastSelectedValues = SelectedValues;
        }
    }

    private async Task ToggleItem(string value)
    {
        if (_selectedItems.Contains(value))
        {
            _selectedItems.Remove(value);
        }
        else
        {
            if (Type == ToggleGroupType.Single)
            {
                _selectedItems.Clear();
            }
            _selectedItems.Add(value);
        }
        StateHasChanged();

        if (Type == ToggleGroupType.Single)
        {
            var outgoing = _selectedItems.FirstOrDefault();
            // Record BEFORE InvokeAsync — a controlled parent re-renders synchronously
            // inside the callback; OnParametersSet must already see this as the value
            // we pushed so it can distinguish an echo from an authoritative override.
            _lastPushedValue = outgoing;
            await ValueChanged.InvokeAsync(outgoing);
        }
        else
        {
            var outgoing = _selectedItems.ToList();
            _lastPushedSelectedValues = outgoing;
            await SelectedValuesChanged.InvokeAsync(outgoing);
        }
    }

    public enum ToggleGroupType { Single, Multiple }
    public enum ToggleGroupVariant { Default, Outline }

    public record ToggleGroupContext(
        ToggleGroupType Type,
        HashSet<string> SelectedItems,
        ToggleGroupVariant Variant,
        Lumeo.Size Size,
        EventCallback<string> Toggle,
        Func<string, bool, string> GetTabIndex,
        List<string> ItemValues,
        Dictionary<string, string> ItemIds,
        Dictionary<string, bool> ItemDisabled,
        // #69: stable-id registration (item id, value, disabled, render generation)
        // so the parent rebuilds ItemValues in DOM order each pass.
        Action<string, string, bool, int> RegisterItem,
        Action<string, string> UnregisterItem,
        // #169: focus-anchor sync — item reports the value it was focused on.
        Action<string> SetFocusValue,
        int Generation,
        // The role=group element id — the anchor for the DOM-order roving-nav probe
        // (Interop.GetOrderedDescendantIds) so arrow-key order tracks the live DOM
        // after a keyed reorder. Always present (LumeoIds.New on the root div).
        string ContainerId)
    {
        public bool IsSelected(string value) => SelectedItems.Contains(value);
    }
}

@namespace Lumeo
@implements IDisposable
@inject Lumeo.Services.IComponentInteropService Interop

<button @ref="_el" id="@_itemId" type="button" data-toggle-item="true" aria-pressed="@IsPressed.ToString().ToLower()" tabindex="@Context.GetTabIndex(Value, Disabled)" class="@CssClass" @onclick="Toggle" @onfocus="OnFocus" disabled="@Disabled" @attributes="AdditionalAttributes">
    @ChildContent
</button>

@code {
    [Parameter, EditorRequired] public string Value { get; set; } = "";
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public bool Disabled { get; set; }

    /// <summary>
    /// Visual feedback when the item is pressed. Default is
    /// <see cref="Button.ButtonPressEffect.None"/>.
    /// </summary>
    [Parameter] public Button.ButtonPressEffect PressEffect { get; set; } = Button.ButtonPressEffect.None;

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    [CascadingParameter] public ToggleGroup.ToggleGroupContext Context { get; set; } = default!;

    private Microsoft.AspNetCore.Components.ElementReference _el;
    private readonly string _itemId = LumeoIds.New("toggle-item");
    private string? _registeredValue;

    private bool IsPressed => Context.SelectedItems.Contains(Value);

    protected override void OnParametersSet()
    {
        if (Context is null) return;

        // #69: register by our STABLE id + the parent's live render generation.
        // The parent owns ordering — it rebuilds its ItemValues list from the
        // sequence these registrations arrive in (= DOM/declaration order for the
        // current render), so insert-at-front and Value renames land in the right
        // slot instead of being appended to the tail. The ownership-guarded re-key
        // lives in the parent (RegisterItem) keyed by _itemId, so two items that
        // share a Value never clobber each other's slot.
        Context.RegisterItem(_itemId, Value, Disabled, Context.Generation);
        _registeredValue = Value;
    }

    // #169 focus-anchor sync: tell the group which item the user actually focused
    // (mouse click lands here, and Tab into the roving tab stop) so the group's
    // arrow-key navigation starts from the real focus, not a stale arrow anchor.
    private void OnFocus()
    {
        Context?.SetFocusValue(Value);
    }

    private string CssClass => Cx.Merge(VariantClasses, SizeClasses, BaseClasses, "cursor-pointer disabled:cursor-not-allowed", PressEffectClass, Class);

    // gap-1.5 mirrors Button's base gap so icon+label children space cleanly without
    // requiring consumers to add Class="gap-1.5" manually. Single-child renders are
    // unaffected (gap only matters when there are multiple flex children).
    private const string BaseClasses = "inline-flex items-center justify-center gap-1.5 rounded-md text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50";

    private string? PressEffectClass => PressEffect switch
    {
        Button.ButtonPressEffect.Scale => "lumeo-press-scale",
        Button.ButtonPressEffect.Brightness => "lumeo-press-brightness",
        Button.ButtonPressEffect.Ripple => "lumeo-press-ripple",
        _ => null
    };

    private string VariantClasses => (Context.Variant, IsPressed) switch
    {
        (ToggleGroup.ToggleGroupVariant.Default, true) => "bg-accent text-accent-foreground",
        (ToggleGroup.ToggleGroupVariant.Default, false) => "bg-transparent hover:bg-muted hover:text-muted-foreground",
        (ToggleGroup.ToggleGroupVariant.Outline, true) => "bg-accent text-accent-foreground border border-input",
        (ToggleGroup.ToggleGroupVariant.Outline, false) => "border border-input bg-transparent hover:bg-accent hover:text-accent-foreground",
        _ => ""
    };

    private string SizeClasses => Context.Size switch
    {
        Lumeo.Size.Sm => "h-8 px-2",
        Lumeo.Size.Lg => "h-10 px-4",
        _ => "h-9 px-3"
    };

    private async Task Toggle()
    {
        if (!Disabled)
        {
            // #169: a click both toggles AND focuses this item — keep the group's
            // focus anchor in sync so a following ArrowRight moves from HERE.
            Context.SetFocusValue(Value);
            await Context.Toggle.InvokeAsync(Value);
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender && PressEffect == Button.ButtonPressEffect.Ripple)
        {
            try
            {
                await Interop.RippleAttachAsync(_el);
            }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
        }
    }

    public void Dispose()
    {
        // Conditionally-removed items must leave the registry (ownership-guarded
        // by stable id inside UnregisterItem so we never delete a sibling's slot).
        if (Context is not null && _registeredValue is not null)
            Context.UnregisterItem(_itemId, _registeredValue);
    }
}
